// PDF parsing utility - using pdf-parse v1.x simple API
import { detectPdfSource, type SourceDetectionResult } from './detect-source';

async function parsePdf(buffer: Buffer): Promise<{ text: string; numpages: number }> {
  // Dynamic require to avoid build-time bundling issues
  // eslint-disable-next-line @typescript-eslint/no-require-imports
  const pdfParse = require('pdf-parse');
  const result = await pdfParse(buffer);
  return { text: result.text, numpages: result.numpages };
}

export interface ParsedCreditData {
  scores: {
    transunion?: number;
    experian?: number;
    equifax?: number;
  };
  accounts: ParsedAccount[];
  negativeItems: ParsedNegativeItem[];
  inquiries: ParsedInquiry[];
  summary: {
    totalAccounts: number;
    openAccounts: number;
    closedAccounts: number;
    totalDebt: number;
    totalCreditLimit: number;
    utilizationPercent: number;
  };
  rawText: string;
  detectedSource?: SourceDetectionResult;
  consumerProfile?: ParsedConsumerProfile;
}

export interface ParsedConsumerProfile {
  names: Array<{
    firstName: string;
    middleName?: string;
    lastName: string;
    suffix?: string;
    bureau?: string;
  }>;
  addresses: Array<{
    street: string;
    city: string;
    state: string;
    zipCode: string;
    addressType?: string;
    dateReported?: Date;
    bureau?: string;
  }>;
  ssnLast4?: string;
  dateOfBirth?: Date;
  employers: Array<{
    name: string;
    dateReported?: Date;
    bureau?: string;
  }>;
}

export type ParsedAccountBureau = 'transunion' | 'experian' | 'equifax';

export interface ParsedAccountBureauEvidence {
  accountNumber?: string;
  accountType?: string;
  accountStatus?: string;
  balance?: number;
  creditLimit?: number;
  highCredit?: number;
  monthlyPayment?: number;
  pastDueAmount?: number;
  paymentStatus?: string;
  dateOpened?: Date;
  dateReported?: Date;
  sourceText?: string;
}

export interface ParsedAccount {
  creditorName: string;
  accountNumber?: string;
  accountType?: string;
  accountStatus?: string;
  balance?: number;
  creditLimit?: number;
  highCredit?: number;
  monthlyPayment?: number;
  pastDueAmount?: number;
  paymentStatus?: string;
  dateOpened?: Date;
  dateReported?: Date;
  bureau?: string;
  bureauEvidence?: Partial<Record<ParsedAccountBureau, ParsedAccountBureauEvidence>>;
  isNegative: boolean;
  riskLevel?: string;
  remarks?: string;
  sourceText?: string;
}

export interface ParsedNegativeItem {
  itemType: string;
  creditorName: string;
  originalCreditor?: string;
  accountNumber?: string; // For linking to credit accounts
  amount?: number;
  dateReported?: Date;
  dateOfLastActivity?: Date; // For DOFD/obsolescence analysis
  dateOfFirstDelinquency?: Date;
  bureauStatedRemovalDate?: Date;
  bureau?: string;
  riskSeverity: string;
}

export interface ParsedInquiry {
  creditorName: string;
  inquiryDate?: Date;
  bureau?: string;
  inquiryType?: string;
}

// Bureau-specific metrics (matching PHP ParserController output)
export interface BureauMetrics {
  creditScore?: number;
  lenderRank?: string;
  scoreScale?: string;
  reportDate?: string;
  totalAccounts: number;
  openAccounts: number;
  closedAccounts: number;
  delinquent: number;
  derogatory: number;
  collection: number;
  balances: number;
  payments: number;
  publicRecords: number;
  inquiries: number;
}

export interface BureauSummary {
  transunion: BureauMetrics;
  experian: BureauMetrics;
  equifax: BureauMetrics;
}

// Credit utilization per bureau
export interface CreditUtilization {
  balance: number;
  limit: number;
  percent: number;
  rating: 'excellent' | 'good' | 'fair' | 'poor' | 'very_poor' | 'no_data';
}

export interface BureauCreditUtilization {
  transunion: CreditUtilization;
  experian: CreditUtilization;
  equifax: CreditUtilization;
  total: CreditUtilization;
}

// Two-year payment history summary per bureau
export interface PaymentHistorySummary {
  lateCount30: number;
  lateCount60: number;
  lateCount90: number;
  lateCount120: number;
  lateCount150: number;
  lateCount180: number;
  chargeOffCount: number;
  collectionCount: number;
  maxLateDays: number; // 0, 30, 60, 90, 120, 150, 180
}

// Derogatory account with per-bureau details
export interface DerogatoryAccount {
  creditorName: string;
  uniqueStatus: string;
  transunion: {
    accountStatus?: string;
    accountDate?: string;
    paymentStatus?: string;
    paymentHistory?: PaymentHistorySummary;
    dateOfFirstDelinquency?: Date;
    bureauStatedRemovalDate?: Date;
  };
  experian: {
    accountStatus?: string;
    accountDate?: string;
    paymentStatus?: string;
    paymentHistory?: PaymentHistorySummary;
    dateOfFirstDelinquency?: Date;
    bureauStatedRemovalDate?: Date;
  };
  equifax: {
    accountStatus?: string;
    accountDate?: string;
    paymentStatus?: string;
    paymentHistory?: PaymentHistorySummary;
    dateOfFirstDelinquency?: Date;
    bureauStatedRemovalDate?: Date;
  };
}

// Public record item
export interface PublicRecord {
  type: string;
  status: string;
  transunionFiled?: string;
  experianFiled?: string;
  equifaxFiled?: string;
}

// Personal information per bureau (matching PHP ParserController output)
export interface PersonalInfoPerBureau {
  name?: string;
  alsoKnownAs?: string[];
  formerName?: string[];
  dateOfBirth?: string;
  currentAddress?: string;
  previousAddresses?: string[];
  employers?: string[];
}

export interface BureauPersonalInfo {
  transunion: PersonalInfoPerBureau;
  experian: PersonalInfoPerBureau;
  equifax: PersonalInfoPerBureau;
}

// Personal information dispute types for generating dispute letters
export type PersonalInfoDisputeType =
  | 'name'
  | 'also_known_as'
  | 'former_name'
  | 'date_of_birth'
  | 'current_address'
  | 'previous_address'
  | 'employer';

export interface PersonalInfoDisputeItem {
  type: PersonalInfoDisputeType;
  bureau: 'transunion' | 'experian' | 'equifax';
  value: string;
}

// Inquiry dispute item for disputing credit inquiries
export interface InquiryDisputeItem {
  type: 'inquiry';
  creditorName: string;
  bureau?: 'transunion' | 'experian' | 'equifax';
  inquiryDate?: Date;
  inquiryType?: string;
  isPastFcraLimit: boolean;
  daysSinceInquiry?: number;
}

// Extended parsed data with bureau-specific details
export interface ExtendedParsedCreditData extends ParsedCreditData {
  bureauSummary?: BureauSummary;
  creditUtilization?: BureauCreditUtilization;
  derogatoryAccounts?: DerogatoryAccount[];
  publicRecords?: PublicRecord[];
  bureauPersonalInfo?: BureauPersonalInfo;

