363: function getBureauFromContext($: cheerio.CheerioAPI, el: Element): 'transunion' | 'experian' | 'equifax' {
364:   const ctx = $(el).parents('[data-bureau]').first().attr('data-bureau') || 
365:     $(el).closest(SC_SELECTORS.bureauSection).text().toLowerCase();
366:   if (ctx.includes('transunion')) return 'transunion';
