380: function parseMoneyValue(val: string | undefined | null): number | undefined {
381:   if (!val) return undefined;
382:   const num = parseFloat(val.replace(/[$,]/g, ''));
383:   return isNaN(num) ? undefined : Math.round(num * 100);
384: }
